function calcIR(m) {
  if (m <= 2824.00) return 0;
  if (m <= 3751.05) return (m - 2824.00) * 0.075;
  if (m <= 4664.68) return (m - 3751.05) * 0.15 + 69.53;
  if (m <= 5800.00) return (m - 4664.68) * 0.225 + 206.57;
  return (m - 5800.00) * 0.275 + 462.02;
}
function fmt(n) { return n.toLocaleString("pt-BR", { style: "currency", currency: "BRL" }); }

